import React, {useEffect, useState} from 'react';
import {AppDataContext} from "./AppDataContext";
import {adminApi, apiInstance} from "../api/api";
import {
  SymbolTrendType,
  BitcoinPublicInformationType,
  createNeuronLearningRequestQueryType,
  CreateSignalTradeRequestQuery,
  NeuronFullType,
  NeuronPublicType,
  NeuronLearningRequestQueryType,
  PlatformFullDictType,
  SignalRequestQueryType,
  SignalTradePropertyType,
  SignalTradeRequestQueryType,
  SymbolPublicWithPlatformPublicType,
  SignalPublicWithSymbolPublicPlatformPublicNeuronMainType,
  SignalFullWithSymbolPublicPlatformPublicNeuronMainType,
  SignalPublicWithSymbolPublicPlatformPublicNeuronMainTradePublicType,
  SignalTraderRequestQueryType,
} from "../types/types";
import {directionEnum} from "../static/static";

type propsType = {
  children: React.ReactNode; // 👈️ type children
};

const initSignalTradePropertyDict: SignalTradePropertyType = {
  init_stop_loss_percent: 5,
  init_treiling_stop_percent: 2,
  init_take_profit_percent: 3,
}

const AppDataProvider = (props: propsType) => {
  const [isAuth, setIsAuth] = useState<boolean>(false);

  const [bitcoinPublicInformation, setBitcoinPublicInformation] = useState<BitcoinPublicInformationType | null>(null)

  const [platformDict, setPlatformDict] = useState<PlatformFullDictType>({})

  const [symbolList, setSymbolList] = useState<SymbolPublicWithPlatformPublicType[]>([])

  const [signalRequestQuery, setSignalRequestQuery] = useState<SignalRequestQueryType>({})
  const [signalPublicList, setSignalPublicList] = useState<SignalPublicWithSymbolPublicPlatformPublicNeuronMainType[]>([])
  const [loadingSignalPublicList, setLoadingSignalPublicList] = useState<boolean>(false)
  const [signalFull, setSignalFull] = useState<SignalFullWithSymbolPublicPlatformPublicNeuronMainType | null>(null)

  const [signalTradeTrendData, setSignalTradeTrendData] = useState<SymbolTrendType | null>(null)
  const [initSignalTradeProperty, setInitSignalTradeProperty] = useState<SignalTradePropertyType>(initSignalTradePropertyDict)

  const [signalTraderRequestQuery, setSignalTraderRequestQuery] = useState<SignalTraderRequestQueryType>({})
  const [signalTraderPublicList, setSignalTraderPublicList] = useState<SignalPublicWithSymbolPublicPlatformPublicNeuronMainTradePublicType[]>([])
  const [loadingSignalTraderPublicList, setLoadingSignalTraderPublicList] = useState<boolean>(false)

  const [neuronLearningRequestQuery, setNeuronLearningRequestQuery] = useState<NeuronLearningRequestQueryType>({})
  const [neuronLearningPublicList, setNeuronNetworkPublicList] = useState<NeuronPublicType[]>([])
  const [loadingNeuronLearningPublicList, setLoadingNeuronLearningPublicList] = useState<boolean>(false)
  const [neuronLearningFull, setNeuronLearningFull] = useState<NeuronFullType | null>(null)

  const [createNeuronLearningRequestQuery, setCreateNeuronLearningRequestQuery] = useState<createNeuronLearningRequestQueryType | null>(null)
  const [loadingCreateNeuronLearning, setLoadingCreateNeuronLearning] = useState<boolean>(false)

  const [signalActiveSearchElement, setSignalActiveSearchElement] = useState<string | null>(null)

  const loginHandler = async (token: string) => {
    apiInstance.createAxiosInstance(token)
    try {
      const response = await adminApi.getBitcoinPublicInformation()
      setBitcoinPublicInformation(response)
      setIsAuth(true)
    } catch (e: any) {
      console.log(e.message)
      apiInstance.createAxiosInstance(null)
      setBitcoinPublicInformation(null)
      setIsAuth(false)
    }
  }

  const logoutHandler = () => {
    apiInstance.createAxiosInstance(null)
    setBitcoinPublicInformation(null)
    setIsAuth(false)
  }

  const getPlatformList = async () => {
    try {
      const response = await adminApi.getPlatformList()
      const draftPlatformDict: PlatformFullDictType = {}
      response.forEach(item => {
        draftPlatformDict[item.platform_name] = item
      })
      setPlatformDict(draftPlatformDict)
    } catch (e: any) {
      console.log(e.message)
    }
  }

  const getActiveSymbolList = async () => {
    try {
      const response = await adminApi.getSymbolList()
      setSymbolList(response)
    } catch (e: any) {
      console.log(e.message)
    }
  }

  const getSignalPublicList = async () => {
    try {
      if (!signalRequestQuery.limit) return;
      setLoadingSignalPublicList(true)
      const response = await adminApi.getSignalList(signalRequestQuery)
      setSignalPublicList(response)
      setLoadingSignalPublicList(false)
    } catch (e: any) {
      console.log(e.message)
    }
  }

  const getSignalTraderPublicList = async () => {
    try {
      if (!signalTraderRequestQuery.limit) return;
      setLoadingSignalTraderPublicList(true)
      const response = await adminApi.getSignalTraderList(signalTraderRequestQuery)
      setSignalTraderPublicList(response)
      setLoadingSignalTraderPublicList(false)
    } catch (e: any) {
      console.log(e.message)
    }
  }

  const getSignalFullByUUID = async (signal_uuid: string) => {
    try {
      const response = await adminApi.getSignalFullByUUID(signal_uuid)
      setSignalFull(response)
    } catch (e: any) {
      console.log(e.message)
    }
  }

  const getSignalTradeByUUID = async (signal_uuid: string) => {
    const payload: SignalTradeRequestQueryType = {
      signal_uuid,
      ...initSignalTradeProperty
    }
    try {
      const response = await adminApi.getSignalTradeByUUID(payload)
      setSignalTradeTrendData(response.symbol_trade_trend)
    } catch (e: any) {
      console.log(e.message)
    }
  }

  const changeInitSignalTradeProperty = (key: string, value: number) => {
    setInitSignalTradeProperty({
      ...initSignalTradeProperty,
      [key as keyof SignalTradePropertyType]: value
    })
  }

  const changeApprovedValueForSignalTrade = async () => {
    if (!signalFull) {
      return null
    }
    try {
      await adminApi.changeApproveValueForSignalTradeByUUID(signalFull.signal_uuid, !signalFull.signal_is_approved)
      const response_full = await adminApi.getSignalFullByUUID(signalFull.signal_uuid)
      setSignalFull(response_full)
    } catch (e: any) {
      console.log(e.message)
    }
  }

  const changeExcludedValueForSignalTrade = async () => {
    if (!signalFull) {
      return null
    }
    try {
      await adminApi.changeExcludeValueForSignalTradeByUUID(signalFull.signal_uuid, !signalFull.signal_is_excluded)
      const response_full = await adminApi.getSignalFullByUUID(signalFull.signal_uuid)
      setSignalFull(response_full)
    } catch (e: any) {
      console.log(e.message)
    }
  }

  const changeDirectionValueForSignalTrade = async (direction: directionEnum) => {
    if (!signalFull) {
      return null
    }
    try {
      await adminApi.changeDirectionValueForSignalTradeByUUID(signalFull.signal_uuid, direction)
      const response_full = await adminApi.getSignalFullByUUID(signalFull.signal_uuid)
      setSignalFull(response_full)
    } catch (e: any) {
      console.log(e.message)
    }
  }

  const createManualSignal = async (signal_uuid: string, delta_timestamp: number) => {
    const payload: CreateSignalTradeRequestQuery = {
      signal_uuid,
      delta_timestamp,
    }
    try {
      const response = await adminApi.createManualSignal(payload)

      await getSignalFullByUUID(response.signal_uuid)
      await getSignalTradeByUUID(response.signal_uuid)

    } catch (e: any) {
      console.log(e.message)
    }
  }

  const removeSignal = async (signal_uuid: string) => {
    try {
      await adminApi.removeSignal(signal_uuid)

      await closeSignalFullModal()
    } catch (e: any) {
      console.log(e.message)
    }
  }

  const openRandomSignalHandler = async () => {
    try {
      const response = await adminApi.getRandomSignal(signalRequestQuery)

      await getSignalFullByUUID(response.signal_uuid)
      await getSignalTradeByUUID(response.signal_uuid)

    } catch (e: any) {
      console.log(e.message)
    }
  }

  const closeSignalFullModal = async () => {
    setSignalFull(null)
    setSignalTradeTrendData(null)

    //await getSignalPublicList()
    await getSignalTraderPublicList()
  }

  const getNeuronLearningPublicList = async () => {
    try {
      setLoadingNeuronLearningPublicList(true)
      const response = await adminApi.getNeuronNetworkPublicList(neuronLearningRequestQuery)
      setNeuronNetworkPublicList(response)
      setLoadingNeuronLearningPublicList(false)
    } catch (e: any) {
      console.log(e.message)
    }
  }

  const startCreatingNeuronLearning = async () => {
    if (!createNeuronLearningRequestQuery) {
      return
    }
    try {
      setLoadingCreateNeuronLearning(true)
      await adminApi.startLearningNeuronNetwork(createNeuronLearningRequestQuery)
      setLoadingCreateNeuronLearning(false)
    } catch (e: any) {
      console.log(e.message)
    }
  }

  const getNeuronLearningFullByUUID = async (neuron_uuid: string) => {
    try {
      const response = await adminApi.getNeuronLearningFullByUUID(neuron_uuid)
      setNeuronLearningFull(response)
    } catch (e: any) {
      console.log(e.message)
    }
  }

  const changeNeuronNetworkAsCurrent = async () => {
    if (!neuronLearningFull) {
      return null
    }
    try {
      await adminApi.changeCurrentValueForNeuronLearningByUUID(neuronLearningFull.neuron_uuid, !neuronLearningFull.neuron_is_current)
      const response_full = await adminApi.getNeuronLearningFullByUUID(neuronLearningFull.neuron_uuid)
      setNeuronLearningFull(response_full)
      const response_public_list = await adminApi.getNeuronNetworkPublicList(neuronLearningRequestQuery)
      setNeuronNetworkPublicList(response_public_list)
    } catch (e: any) {
      console.log(e.message)
    }
  }

  const closeNeuronLearningFullModal = () => {
    setNeuronLearningFull(null)
  }

  useEffect(() => {
    isAuth && getPlatformList()
    isAuth && getActiveSymbolList()
  }, [isAuth])

  useEffect(() => {
    isAuth && getSignalPublicList()
  }, [isAuth, signalRequestQuery])

  useEffect(() => {
    isAuth && getSignalTraderPublicList()
  }, [isAuth, signalTraderRequestQuery])

  useEffect(() => {
    isAuth && getNeuronLearningPublicList()
  }, [isAuth, neuronLearningRequestQuery])

  useEffect(() => {
    isAuth && startCreatingNeuronLearning()
  }, [isAuth, createNeuronLearningRequestQuery])

  const value = {
    isAuth,

    bitcoinPublicInformation,

    platformDict,

    symbolList,

    signalPublicList,
    loadingSignalPublicList,
    signalFull,

    signalTradeTrendData,
    initSignalTradeProperty,

    signalTraderPublicList,
    loadingSignalTraderPublicList,

    neuronLearningPublicList,
    neuronLearningFull,

    loadingCreateNeuronLearning,
    loadingNeuronLearningPublicList,

    signalActiveSearchElement,

    loginHandler,
    logoutHandler,

    getPlatformList,

    getActiveSymbolList,

    setSignalRequestQuery,
    getSignalFullByUUID,
    getSignalTradeByUUID,

    setSignalTraderRequestQuery,

    changeInitSignalTradeProperty,
    changeApprovedValueForSignalTrade,
    changeExcludedValueForSignalTrade,
    changeDirectionValueForSignalTrade,

    closeSignalFullModal,

    createManualSignal,

    removeSignal,

    openRandomSignalHandler,

    setNeuronLearningRequestQuery,
    getNeuronLearningFullByUUID,

    changeNeuronNetworkAsCurrent,

    closeNeuronLearningFullModal,

    setCreateNeuronLearningRequestQuery,

    setSignalActiveSearchElement,
  }

  return (
    <AppDataContext.Provider value={value}>
      {props.children}
    </AppDataContext.Provider>
  );
};

export { AppDataProvider };
