import {useContext} from "react";
import cs from "./styles.module.css";
import {AppDataContext} from "../context/AppDataContext";
import {NeuronLearningPublicItem} from "../components/neuronLearningPublicItem/NeuronLearningPublicItem";

const Neurons = () => {
  const value = useContext(AppDataContext);

  const neuronLearningPublicItems = value?.neuronLearningPublicList.map(item =>
    <NeuronLearningPublicItem neuron={item} key={item.neuron_uuid}/>
  )

  return (
    <div className={cs.list}>
      {neuronLearningPublicItems}
    </div>
  )
}

export {Neurons}
